// Keep only these SharePoint field names
const objectType = "job";
const keepFields = [
  ...($json.n8n_sharepoint.lists[objectType].fields || []),
  ...($json.n8n_sharepoint.lists[objectType].readonly || [])
];

const fields = $json?.fields ?? $json;
const ID = $json.id || $json.ID;
const JobNumber = fields.Title;
const JobTitle = `Ref: ${fields.JobNumber} (${fields.AddressLine1 ?? ''}, ${fields.Postcode ?? ''})`;

const item = Object.fromEntries(
  Object.entries(fields).filter(([k]) => keepFields.includes(k))
);

// Find the includes and split to an array
const include = ($('EntryPoint').item.json.include ?? '')
     .split(',')
     .map(s => s.trim().toLowerCase());

return {
  json: {
    [objectType]: {
      ID,
      JobNumber,
      ...item
    },
    include,
    /*related: {
      property: null,
      email: [],
      attachment: []
    },*/
    n8n_sharepoint: $json.n8n_sharepoint
  }
};

// Keep only these SharePoint field names
const objectType = "property";
const sharepointSettings = $('Wrap job').first().json.n8n_sharepoint;
const keepFields = sharepointSettings.lists[objectType].fields || [];

function safeParseJson(str) {
  if (!str || typeof str !== "string") return null;
  try {
    return JSON.parse(str);
  } catch {
    return null;
  }
}

const items = $input.all()
  .map(i => {
    const f = i.json?.fields ?? i.json;
    if (!f) return null;

    const item = Object.fromEntries(
      Object.entries(f).filter(([k]) => keepFields.includes(k))
    );

    //item.QuoteObject = safeParseJson(item.QuoteDetail);

    return item;
  })
  .filter(Boolean)
  .sort((a, b) => (Number(b.Created) || 0) - (Number(a.Created) || 0));

if (!items.length) return [];

return [
  {
    json: {
      relatedItem: {
        key: `${objectType}`,
        value: items.pop()
      }
    }
  }
];

const items = $input.all();

const emails = items
  .map(i => {
    const f = i.json?.fields ?? i.json;
    if (!f) return null;

    return {
      id: i.json.id ?? f.ID,
      From: f.From,
      Subject: f.Subject ?? f.Title,
      Body: f.Body,
      BodyHtml: f.BodyHtml,
      ThreadSummary: f.ThreadSummary,
      ReceivedDate: f.ReceivedDate ? new Date(f.ReceivedDate).toISOString() : null,
      OutlookUrl: f.OutlookUrl,
      ThreadUrl: f.Thread
    };
  })
  .filter(Boolean)
  .sort((a, b) => new Date(b.ReceivedDate) - new Date(a.ReceivedDate));

if (!emails.length) return [];

return {
  json: {
    relatedItem: {
      key: "email",
      value: emails
    }
  }
};

const base = $('Wrap job').first().json;
const items = $input.all();

const requested = (
  Array.isArray(base.include)
    ? base.include
    : String(base.include ?? "")
        .split(",")
).filter(Boolean);

const related = { ...(base.related ?? {}) };
const resolved = [];

for (const item of items) {
  const r = item.json?.relatedItem;
  if (!r?.key) continue;

  const key = r.key;

  related[key] = r.value;

  if (!resolved.includes(key)) {
    resolved.push(key);
  }
}

const missing = requested.filter(key => !resolved.includes(key));

return [
  {
    json: {
      ...base,
      include: requested,
      related,
      meta: {
        requested,
        resolved,
        missing
      }
    }
  }
];

