if (!attachments.length) {
  return [];
}

return [
  {
    json: {
      relatedItem: {
        key: "attachment",
        value: attachments
      }
    }
  }
];

function extOf(name = "") {
  const m = String(name).toLowerCase().match(/\.([a-z0-9]+)$/i);
  return m ? m[1] : "";
}

function prettySize(bytes) {
  const n0 = Number(bytes);
  if (!Number.isFinite(n0)) return "";

  const units = ["B", "KB", "MB", "GB", "TB"];
  let i = 0;
  let n = n0;

  while (n >= 1024 && i < units.length - 1) {
    n /= 1024;
    i++;
  }

  return `${n.toFixed(i === 0 ? 0 : 1)} ${units[i]}`;
}

function iconForExt(ext = "") {
  const e = ext.toLowerCase();

  if (["png","jpg","jpeg","gif","webp","bmp","tif","tiff","svg"].includes(e)) return "fa-regular fa-image";
  if (e === "pdf") return "fa-regular fa-file-pdf";
  if (["doc","docx","rtf"].includes(e)) return "fa-regular fa-file-word";
  if (["xls","xlsx","csv"].includes(e)) return "fa-regular fa-file-excel";
  if (["ppt","pptx"].includes(e)) return "fa-regular fa-file-powerpoint";
  if (["eml","msg"].includes(e)) return "fa-regular fa-envelope";
  if (["zip","7z","rar","tar","gz"].includes(e)) return "fa-regular fa-file-zipper";
  if (["txt","log"].includes(e)) return "fa-regular fa-file-lines";
  if (["json","xml","yaml","yml"].includes(e)) return "fa-regular fa-file-code";

  return "fa-regular fa-file";
}

function previewKindFor(mimeType = "", ext = "") {
  const e = ext.toLowerCase();

  const isImage =
    mimeType.startsWith("image/") ||
    ["png","jpg","jpeg","gif","webp","bmp","tif","tiff","svg"].includes(e);

  const isPdf =
    mimeType === "application/pdf" || e === "pdf";

  if (isImage) return "image";
  if (isPdf) return "iframe";

  return "external";
}

function groupRank(a) {
  if (a.previewKind === "image") return 0;
  if (a.ext === "PDF") return 1;
  if (a.ext === "EML" || a.ext === "MSG") return 3;
  return 2; // office docs, etc
}

const items = $input.all();

const attachments = items
  .map(item => {
    const file = item.json;
    if (!file?.isFile) return null;

    const ext = extOf(file.name);
    const mimeType = file.file?.mimeType ?? "";

    const thumbUrl =
      file.thumbnails?.[0]?.small?.url ??
      file.thumbnails?.[0]?.medium?.url ??
      null;

    const isImage =
      mimeType.startsWith("image/") ||
      ["png","jpg","jpeg","gif","webp","bmp","tif","tiff","svg"].includes(ext);

    const previewUrl = isImage
      ? (file.webUrl ?? "")
      : (file.getUrl ?? file.webUrl ?? "");

    return {
      id: file.id ?? null,
      name: file.name ?? "",
      webUrl: file.webUrl ?? "",
      size: file.size ?? null,
      sizeText: prettySize(file.size),
      mimeType,
      ext: ext.toUpperCase(),
      icon: iconForExt(ext),
      thumbUrl,
      previewKind: previewKindFor(mimeType, ext),
      previewUrl,
      created: file.createdDateTime ?? "",
      modified: file.lastModifiedDateTime ?? "",
      parentPath: file.parentPath
    };
  })
  .filter(Boolean)
  .sort((a, b) =>
    groupRank(a) - groupRank(b) ||
    String(b.modified ?? "").localeCompare(String(a.modified ?? ""))
  );

if (!attachments.length) {
  return [];
}

return [
  {
    json: {
      relatedItem: {
        key: "file",
        value: attachments
      }
    }
  }
];

function safeParseJson(str) {
  if (!str || typeof str !== "string") return null;
  try {
    return JSON.parse(str);
  } catch {
    return null;
  }
}

const input = safeParseJson($('Wrap job').first().json.job.SpFilesJson)?.items || [];

return input;
